import{_ as t,o as l,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"菲尔·利切 · Phil Liesche","description":"","frontmatter":{},"headers":[],"relativePath":"04_people/子公司CEO/菲尔·利切.md","filePath":"04_people/子公司CEO/菲尔·利切.md"}'),i={name:"04_people/子公司CEO/菲尔·利切.md"};function o(h,a,n,s,d,c){return l(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="菲尔·利切-·-phil-liesche" tabindex="-1">菲尔·利切 · Phil Liesche <a class="header-anchor" href="#菲尔·利切-·-phil-liesche" aria-label="Permalink to &quot;菲尔·利切 · Phil Liesche&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Philip Liesche（菲尔·利切）</td></tr><tr><td><strong>职位</strong></td><td>国家赔偿公司（National Indemnity Company）CEO</td></tr><tr><td><strong>任职期间</strong></td><td>1967年收购后至1980年代</td></tr><tr><td><strong>历史地位</strong></td><td>伯克希尔保险业务的奠基人之一</td></tr></tbody></table><h2 id="与巴菲特的关系" tabindex="-1">与巴菲特的关系 <a class="header-anchor" href="#与巴菲特的关系" aria-label="Permalink to &quot;与巴菲特的关系&quot;">​</a></h2><p>1967年，巴菲特以860万美元收购国家赔偿公司，菲尔·利切作为原有管理层留任。他是巴菲特进入保险行业的&quot;最初赌注&quot;，并在随后十几年里<strong>远超预期</strong>地证明了巴菲特的眼光。</p><h2 id="历年股东信提及" tabindex="-1">历年股东信提及 <a class="header-anchor" href="#历年股东信提及" aria-label="Permalink to &quot;历年股东信提及&quot;">​</a></h2><h3 id="_1977年" tabindex="-1">1977年 <a class="header-anchor" href="#_1977年" aria-label="Permalink to &quot;1977年&quot;">​</a></h3><blockquote><p>我们的保险业务——尤其是国家赔偿公司由<strong>菲尔·利切</strong>领导的管理团队取得的非凡业绩——甚至比我们最乐观的预期还要好。</p></blockquote><blockquote><p>我们必须再次感谢<strong>菲尔·利切</strong>，在核保得到罗兰·米勒、理赔得到比尔·莱昂斯的大力协助下，1977年国家赔偿传统汽车和一般责任业务取得了非凡的承保业绩。</p></blockquote><p><strong>核心贡献</strong>：</p><ul><li>在1974-1975年行业危机后，竞争对手收缩或退出</li><li>国家赔偿逆势扩张，业务量大增</li><li>同时保持优秀的承保利润率</li><li>为伯克希尔贡献大量可用于投资的保险浮存金</li></ul><h3 id="_1978年" tabindex="-1">1978年 <a class="header-anchor" href="#_1978年" aria-label="Permalink to &quot;1978年&quot;">​</a></h3><p>巴菲特继续赞扬菲尔·利切在保险承保上的纪律性：</p><blockquote><p>当市场再次宽松、费率变得不再合理时，我们将再次面临哲学层面上接受业务量下降的挑战。这需要非同寻常的管理纪律。</p></blockquote><p>菲尔·利切展现了罕见的品质：<strong>宁可牺牲业务量，也不做亏本生意</strong>。</p><h2 id="核心贡献" tabindex="-1">核心贡献 <a class="header-anchor" href="#核心贡献" aria-label="Permalink to &quot;核心贡献&quot;">​</a></h2><h3 id="_1-证明保险业务的潜力" tabindex="-1">1. 证明保险业务的潜力 <a class="header-anchor" href="#_1-证明保险业务的潜力" aria-label="Permalink to &quot;1. 证明保险业务的潜力&quot;">​</a></h3><p>1967年收购时，国家赔偿年保费2200万美元。 1977年，伯克希尔保险业务总保费达1.51亿美元——增长近600%，<strong>没有增发任何新股</strong>。</p><h3 id="_2-建立承保纪律" tabindex="-1">2. 建立承保纪律 <a class="header-anchor" href="#_2-建立承保纪律" aria-label="Permalink to &quot;2. 建立承保纪律&quot;">​</a></h3><p>保险行业的陷阱：当市场火热时，大家争抢业务，压低费率；当市场转冷时，亏损显现。</p><p>菲尔·利切的管理哲学：</p><ul><li>顺风时扩张</li><li>逆风时收缩</li><li><strong>绝不为了规模牺牲利润率</strong></li></ul><p>这种纪律后来成为伯克希尔保险业务的基因。</p><h3 id="_3-培养保险浮存金" tabindex="-1">3. 培养保险浮存金 <a class="header-anchor" href="#_3-培养保险浮存金" aria-label="Permalink to &quot;3. 培养保险浮存金&quot;">​</a></h3><p>保险业务的核心价值不仅是承保利润，更是<strong>浮存金</strong>——客户预交的保费，理赔前可用于投资。</p><p>菲尔·利切时代的国家赔偿，为巴菲特提供了宝贵的&quot;免费杠杆&quot;。</p><h2 id="管理风格特点" tabindex="-1">管理风格特点 <a class="header-anchor" href="#管理风格特点" aria-label="Permalink to &quot;管理风格特点&quot;">​</a></h2><p>根据巴菲特描述，菲尔·利切的特点：</p><ol><li><strong>承保纪律严明</strong> - 不合理的价格不接</li><li><strong>成本控制</strong> - 保持低运营成本</li><li><strong>团队协作</strong> - 罗兰·米勒（核保）、比尔·莱昂斯（理赔）</li><li><strong>长期主义</strong> - 不为短期业务量牺牲长期利润</li></ol><h2 id="历史地位" tabindex="-1">历史地位 <a class="header-anchor" href="#历史地位" aria-label="Permalink to &quot;历史地位&quot;">​</a></h2><p>在伯克希尔发展史上，菲尔·利切是<strong>被低估的关键人物</strong>：</p><ul><li>他是巴菲特进入保险行业的第一个赌注</li><li>他证明了保险业务可以成为伯克希尔的&quot;引擎&quot;</li><li>他建立的承保纪律影响至今</li></ul><p>没有菲尔·利切的超额表现，伯克希尔可能不会在保险业务上持续加注，也就不会有后来GEICO、Ajit Jain（阿吉特·贾恩）的故事。</p><h2 id="相关公司" tabindex="-1">相关公司 <a class="header-anchor" href="#相关公司" aria-label="Permalink to &quot;相关公司&quot;">​</a></h2><ul><li><a href="/03_companies/国家赔偿公司.html">国家赔偿公司</a> - 任职CEO</li><li><a href="/search.html?q=伯克希尔·哈撒韦">伯克希尔·哈撒韦</a> - 母公司</li></ul><h2 id="相关人物" tabindex="-1">相关人物 <a class="header-anchor" href="#相关人物" aria-label="Permalink to &quot;相关人物&quot;">​</a></h2><ul><li><a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a> - 老板，收购决策者</li><li><a href="/search.html?q=罗兰·米勒">罗兰·米勒</a> - 核保负责人，搭档</li><li><a href="/search.html?q=比尔·莱昂斯">比尔·莱昂斯</a> - 理赔负责人，搭档</li><li><a href="/04_people/阿吉特·贾恩.html">阿吉特·贾恩</a> - 后来者，伯克希尔保险业务的接班人</li></ul><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li><a href="/search.html?q=保险业务">保险业务</a> - 伯克希尔核心板块</li><li><a href="/search.html?q=承保纪律">承保纪律</a> - 菲尔·利切的核心贡献</li><li><a href="/search.html?q=浮存金">浮存金</a> - 保险业务的投资价值</li></ul><h2 id="扩展阅读" tabindex="-1">扩展阅读 <a class="header-anchor" href="#扩展阅读" aria-label="Permalink to &quot;扩展阅读&quot;">​</a></h2><ul><li>1967年股东信：巴菲特收购国家赔偿的决策过程</li><li>1977年股东信：菲尔·利切的非凡表现</li><li>《滚雪球》：保险业务如何改变伯克希尔</li></ul><hr><blockquote><p>链接：<a href="/03_companies/国家赔偿公司.html">国家赔偿公司</a> | <a href="/search.html?q=保险业务">保险业务</a> | <a href="/search.html?q=1977年巴菲特致股东的信">1977年巴菲特致股东的信</a></p></blockquote><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/1977年/翻译.html">1977年</a></li><li><a href="./../01_letters/1978年/翻译.html">1978年</a></li><li><a href="./../01_letters/1979年/翻译.html">1979年</a></li><li><a href="./../01_letters/1980年/翻译.html">1980年</a></li><li><a href="./../01_letters/1981年/翻译.html">1981年</a></li><li><a href="./../01_letters/1982年/翻译.html">1982年</a></li></ul>',45)])])}const q=t(i,[["render",o]]);export{p as __pageData,q as default};
